    public void setRemarkDatetoMap(Map _projRemarkMap)
    {
        Query                               query;
        QueryRun                            qr;
        QueryBuildDataSource                qbds;
        Cent_ProjectRevenuePidView          projectRevenuePidView;
        
        str                     currentPID;
        str                     previousPID = "";
        str                     concatenatedRemark = "";
        boolean                 isFirstRecord = true;

        while select projectRevenuePidView
            order by projectRevenuePidView.ProjId
            where projectRevenuePidView.CategoryId == "True Up_Fee"
        {
            currentPID = projectRevenuePidView.ProjId;
            
            if (!isFirstRecord && currentPID != previousPID)
            {   
                _projRemarkMap.insert(previousPID, concatenatedRemark);
                concatenatedRemark = "";
            }

            if (concatenatedRemark != "")
            {
                concatenatedRemark += "," + projectRevenuePidView.Remark;
            }
            else
            {
                concatenatedRemark = projectRevenuePidView.Remark;
            }

            previousPID = currentPID;
            isFirstRecord = false;
        }

        if (!isFirstRecord)
        {
            _projRemarkMap.insert(previousPID, concatenatedRemark);
        }
    }

    public void insertProjectRevenueInquire(Cent_ProjectRevenueContract _dataContract)
    {
        RecordInsertList projectRevenueLineTableList = new RecordInsertList(tableNum(Cent_ProjectRevenueLineTable));

        Cent_ProjectRevenueTable        projectRevenueTable;
        Cent_ProjectRevenueLineTable    projectRevenueLineTable;

        QueryBuildDataSource            projectRevenueTempSumDS;
        str projLegal = _dataContract.parmMultiDateCompanies();
        ProjId            projId = _dataContract.parmProjId();
        Cent_TotalAmountType    totalAmountType = _dataContract.parmTotalAmountType();
        Name                    proDemsionC1 = _dataContract.parmProDemsionC1();

        Date1980    projectDate = _dataContract.parmProjectDate();
        InvoiceDate invoiceStartDate = dateStartMth(projectDate);
        InvoiceDate invoiceEndDate = dateEndMth(projectDate);

        Cent_MainOrSubType  mainOrSubType = _dataContract.parmCent_MainOrSubType();
        str id = guid2Str(newGuid());

        projectRevenueTable.clear();
        projectRevenueTable.Id = id;
        projectRevenueTable.Locked = NoYes::No;
        projectRevenueTable.StartDate = invoiceStartDate;
        projectRevenueTable.EndDate = invoiceEndDate;
        projectRevenueTable.UpdateUser = UserInfoHelp::userName(curUserId());
        projectRevenueTable.UpdateDateTime = DateTimeUtil::utcNow();
        projectRevenueTable.MainOrSubType = mainOrSubType;
        projectRevenueTable.insert();

        Map projRemarkMap = new Map(Types::String, Types::String);
        this.setRemarkDatetoMap(projRemarkMap);

        Query query = new Query(queryStr(Cent_ProjectRevenueQuery));
        query.allowCrossCompany(true);
        if(projLegal)
        {
            container entityCon = str2con(projLegal, ',');
            int no = 1;
            while (no <= conlen(entityCon))
            {
                query.addCompanyRange(conPeek(entityCon, no));
                no++;
            }
        }
        projectRevenueTempSumDS =  query.dataSourceTable(tableNum(Cent_ProjectRevenueTempSumTable));

        if (projId)
        {
            projectRevenueTempSumDS.addRange(fieldNum(Cent_ProjectRevenueTempSumTable, ProjId)).value(queryValue(projId));
        }

        if (totalAmountType == Cent_TotalAmountType::Yes)
        {
            projectRevenueTempSumDS.addRange(fieldNum(Cent_ProjectRevenueTempSumTable, AmountCur)).value(SysQuery::valueNot(0));
        }

        if (proDemsionC1)
        {
            projectRevenueTempSumDS.addRange(fieldNum(Cent_ProjectRevenueTempSumTable, Dimension_C1)).value(queryValue(proDemsionC1));
        }
        QueryRun queryRun = new QueryRun(query);

        while (queryRun.next())
        {
            projectRevenueTempSumTable = queryRun.get(tableNum(Cent_ProjectRevenueTempSumTable));

            
            changecompany(projectRevenueTempSumTable.DataArea)
            {
                if (totalAmountType == Cent_TotalAmountType::Yes && projectRevenueTempSumTable.AmountCur == 0)
                {
                    continue;
                }
                projectRevenueLineTable.clear();
                projectRevenueLineTable.Id = id;
                projectRevenueLineTable.AccountMan = projectRevenueTempSumTable.AccountMan;
                projectRevenueLineTable.DataArea = strUpr(projectRevenueTempSumTable.DataArea);
                projectRevenueLineTable.AmountCur = projectRevenueTempSumTable.AmountCur;
                projectRevenueLineTable.ProjId = projectRevenueTempSumTable.ProjId;
                projectRevenueLineTable.TransDateMonth = projectRevenueTempSumTable.TransDateMonth;
                projectRevenueLineTable.ProductLine = projectRevenueTempSumTable.ProductLine;
                projectRevenueLineTable.VNSCustClassificationId = projectRevenueTempSumTable.VNSCustClassificationId;
                projectRevenueLineTable.Dimension_C1 = projectRevenueTempSumTable.Dimension_C1;
                projectRevenueLineTable.CustomerName = projectRevenueTempSumTable.CustomerName;
                projectRevenueLineTable.CustAccount = projectRevenueTempSumTable.CustAccount;
                projectRevenueLineTable.BOName = projectRevenueTempSumTable.BOName;
                projectRevenueLineTable.WorkerResponsible = projectRevenueTempSumTable.WorkerResponsible;
                projectRevenueLineTable.MainORSub = projectRevenueTempSumTable.MainORSub;
                projectRevenueLineTable.Subconc = projectRevenueTempSumTable.Subconc;
                projectRevenueLineTable.ResourceCompanyId = strUpr(projectRevenueTempSumTable.ResourceCompanyId);
                projectRevenueLineTable.Name = projectRevenueTempSumTable.Name;
                projectRevenueLineTable.Dimension_C3 = projectRevenueTempSumTable.Dimension_C3;
                projectRevenueLineTable.Dimension_CCC = projectRevenueTempSumTable.Dimension_CCC;
                projectRevenueLineTable.RevenueType = projectRevenueTempSumTable.RevenueType;
                projectRevenueLineTable.ProjGroupId = projectRevenueTempSumTable.ProjGroupId;
                projectRevenueLineTable.CurrencyId = projectRevenueTempSumTable.CurrencyId;
                projectRevenueLineTable.OverdueTrueCur = projectRevenueTempSumTable.OverdueTrueCur;
                projectRevenueLineTable.InvoiceTrueCur = projectRevenueTempSumTable.InvoiceTrueCur;
                projectRevenueLineTable.OtherTrueCur = projectRevenueTempSumTable.OtherTrueCur;

                if (projectRevenueLineTable.MainORSub == Cent_MainOrSubType::Sub)
                {
                    projectRevenueLineTable.TaxAmountCur = projectRevenueTempSumTable.TaxAmountCur;
                    projectRevenueLineTable.TaxAmountUSDCur = projectRevenueTempSumTable.TaxAmountUSDCur;
                    projectRevenueLineTable.TotalAmountCur = projectRevenueTempSumTable.TotalAmountCur;
                    projectRevenueLineTable.TotalAmountUSDCur = projectRevenueTempSumTable.TotalAmountUSDCur;
                    projectRevenueLineTable.RevenueIncludeCur = projectRevenueTempSumTable.RevenueIncludeCur;
                    projectRevenueLineTable.RevenueIncludeVATCur = projectRevenueTempSumTable.RevenueIncludeVATCur;
                }
                else
                {
                    if (SysCountryRegionCode::isLegalEntityInCountryRegion([#isoCN]))
                    {
                        projectRevenueLineTable.TaxAmountCur = projectRevenueTempSumTable.TaxAmountCur;
                        projectRevenueLineTable.TaxAmountUSDCur = projectRevenueTempSumTable.TaxAmountUSDCur;
                        projectRevenueLineTable.TotalAmountCur = projectRevenueTempSumTable.TotalAmountCur;
                        projectRevenueLineTable.TotalAmountUSDCur = projectRevenueTempSumTable.TotalAmountUSDCur;
                        projectRevenueLineTable.RevenueIncludeCur = projectRevenueTempSumTable.RevenueIncludeCur;
                        projectRevenueLineTable.RevenueIncludeVATCur = projectRevenueTempSumTable.RevenueIncludeVATCur;
                    }
                    else
                    {
                        projectRevenueLineTable.TaxAmountCur = 0;
                        projectRevenueLineTable.TaxAmountUSDCur = 0;
                        projectRevenueLineTable.TotalAmountCur = projectRevenueTempSumTable.TotalAmountCur;
                        projectRevenueLineTable.TotalAmountUSDCur = projectRevenueTempSumTable.TotalAmountUSDCur;
                        projectRevenueLineTable.RevenueIncludeCur = projectRevenueTempSumTable.TotalAmountCur;
                        projectRevenueLineTable.RevenueIncludeVATCur = projectRevenueTempSumTable.TotalAmountUSDCur;
                    }

                    if (projectRevenueTempSumTable.DataArea == identifierStr(PTTW))
                    {
                        projectRevenueLineTable.AmountCur = projectRevenueTempSumTable.AmountCur;
                        projectRevenueLineTable.TaxAmountUSDCur = projectRevenueTempSumTable.TaxAmountUSDCur;
                        projectRevenueLineTable.TotalAmountUSDCur = projectRevenueTempSumTable.TotalAmountUSDCur;
                        projectRevenueLineTable.RevenueIncludeVATCur = projectRevenueTempSumTable.RevenueIncludeVATCur;
                    }
                }

                if (projectRevenueTempSumTable.DataArea == identifierStr(PTTW))
                {
                    if (projectRevenueTempSumTable.TaxGroupId)
                    {
                        projectRevenueLineTable.TaxAmountCur = decRound(projectRevenueTempSumTable.TaxAmountCur, 0);
                        projectRevenueLineTable.TotalAmountCur = decRound(projectRevenueTempSumTable.TotalAmountCur, 0);
                        projectRevenueLineTable.RevenueIncludeCur = decRound(projectRevenueTempSumTable.RevenueIncludeCur, 0);
                    }
                    else
                    {
                        projectRevenueLineTable.TaxAmountCur = projectRevenueTempSumTable.TaxAmountCur;
                        projectRevenueLineTable.TotalAmountCur = projectRevenueTempSumTable.TotalAmountCur;
                        projectRevenueLineTable.RevenueIncludeCur = projectRevenueTempSumTable.RevenueIncludeCur;
                    }
                }
                
                if (projRemarkMap.exists(projectRevenueLineTable.ProjId))
                {
                    projectRevenueLineTable.Remark = projRemarkMap.lookup(projectRevenueLineTable.ProjId);
                }
                else
                {
                    projectRevenueLineTable.Remark = projectRevenueTempSumTable.Remark;
                }
                projectRevenueLineTable.ExchangeRate = projectRevenueTempSumTable.ExchangeRate;
                projectRevenueLineTable.TaxGroupId = projectRevenueTempSumTable.TaxGroupId;
                projectRevenueLineTable.TaxRate = projectRevenueTempSumTable.TaxRate;
                projectRevenueLineTable.InvoiceMainType = NoYes::No;
                projectRevenueLineTableList.add(projectRevenueLineTable);
            }
        }
        projectRevenueLineTableList.insertDatabase();
    }

    public boolean checkProjectRevenueTable(Cent_ProjectRevenueContract _dataContract)
    {
        MenuItemName menuItem = _dataContract.parmMenuItemName();

        Date1980          projectDate = _dataContract.parmProjectDate();

        InvoiceDate dateStartMonth = dateStartMth(projectDate);
        InvoiceDate dateEndMonth = dateEndMth(projectDate);
    
        if (menuItem == menuItemActionStr(Cent_ProjectRevenueInquireMenu) && Cent_ProjectRevenueTable::exist(dateStartMonth, dateEndMonth))
        {
            return false;
        }

        return true;
    }
